import pytest

def test_create_payroll_run_missing_mandatory_fields_returns_400(admin_auth_token, api_client):
    resp = api_client.post(
        "/payroll-runs",
        json={},
        headers={"Authorization": f"Bearer {admin_auth_token}"}
    )
    assert resp.status_code == 400, f"Expected 400, got {resp.status_code}"
    body = resp.json()
    assert "errors" in body or "message" in body, (
        "400 response must contain validation error details"
    )

