def test_create_payroll_run_unauthenticated_returns_401(api_client):
    payload = {
        "period_name": "Unauthenticated-Period",
        "start_date": "2024-08-01",
        "end_date": "2024-08-31",
        "currency": "USD"
    }
    resp = api_client.post("/payroll-runs", json=payload)
    assert resp.status_code == 401, f"Expected 401 for unauthenticated request, got {resp.status_code}"

