def test_create_payroll_run_non_admin_role_returns_403(employee_auth_token, api_client):
    payload = {
        "period_name": "Employee-Attempt-Period",
        "start_date": "2024-09-01",
        "end_date": "2024-09-30",
        "currency": "USD"
    }
    resp = api_client.post(
        "/payroll-runs",
        json=payload,
        headers={"Authorization": f"Bearer {employee_auth_token}"}
    )
    assert resp.status_code == 403, f"Expected 403 for non-admin role, got {resp.status_code}"
